import { describe, expect, it } from 'vitest';
import { createTestHarness, type TestHarnessAuthorResponse } from '@simodelne/pgas-server/testing.js';
import { createIncidentEscalationProgramEntry } from '../src/programs/incident-escalation/registration.js';

describe('generated program smoke', () => {
  it('runs Incident Escalation through the deterministic completion path without stub output', async () => {
    const harness = await createTestHarness(createIncidentEscalationProgramEntry(), {
      programName: 'incident-escalation',
      defaultChannel: 'user_text',
      authorResponses: [
        effect('begin_work', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_severity_score', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_pagerduty_adapter', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_remediation_summary', {
          result_json: JSON.stringify({"decision":"proceed","summary":"sample summary","rationale":"sample rationale","confidence":"low","key_points":["sample key points"]}),
          items_json: JSON.stringify(["remediation_summary:decision:proceed","remediation_summary:confidence:low"]),
          decision: "proceed",
          summary: "sample summary",
          rationale: "sample rationale",
          confidence: "low",
          key_points: "[\"sample key points\"]",
        }, 'widget_output'),
      ],
    });

    try {
      await harness.trigger('start generated smoke');
      await harness.trigger('continue generated smoke');
      await harness.trigger('continue generated smoke');
      await harness.trigger('continue generated smoke');
      const snapshot = await harness.snapshot();
      expect(snapshot.mode).toBe('closed');
      const serialized = JSON.stringify(snapshot.domain).toLowerCase();
      expect(serialized).not.toContain('stage_action_stub');
      expect(serialized).not.toContain('"todo"');
      expect(serialized).toContain('in_memory_mock');
    } finally {
      await harness.close();
    }
  });
});

function effect(name: string, payload: Record<string, unknown>, channel?: string): TestHarnessAuthorResponse {
  return { actions: [{ kind: 'EffectAction', name, channel: channel ?? (name === 'begin_work' ? 'widget_output' : 'stage_output'), payload }] };
}
